INSERT INTO `v1_2bf8b5e1ed46c8c27bd2f7d2b88c03d0f264cc81d9ddb511c67e86d90bf244c5` VALUES (1, 2, "アヤネ", "", 0, 1, "", 1, 1, "---");
INSERT INTO `v1_2bf8b5e1ed46c8c27bd2f7d2b88c03d0f264cc81d9ddb511c67e86d90bf244c5` VALUES (0, 1, "アサヒ", "逆境に屈することなく、部員たちを引っ張る主将。ミート力を活かした安定感のある打撃が持ち味。", 6000, 1, "", 3, 2, "---");
INSERT INTO `v1_2bf8b5e1ed46c8c27bd2f7d2b88c03d0f264cc81d9ddb511c67e86d90bf244c5` VALUES (3, 3, "部員3", "無愛想だが仲間を大切に想う気持ちは誰よりも強い男。ケンカで鍛えた腕っぷしが自慢のパワーヒッター。", 16000, 1, "ホームランを連発すると、連発数に応じてパワーアップする", 0, 3, "アドレナリン");
INSERT INTO `v1_2bf8b5e1ed46c8c27bd2f7d2b88c03d0f264cc81d9ddb511c67e86d90bf244c5` VALUES (2, 2, "{0}", "みんなからの厚い信頼を集める期待の助っ人部員。実力は未知数だが幸運なハプニングを呼び込む。", 30000, 1, "幸運のハプニングを呼び込む", 2, 4, "ラッキー");
INSERT INTO `v1_2bf8b5e1ed46c8c27bd2f7d2b88c03d0f264cc81d9ddb511c67e86d90bf244c5` VALUES (1, 0, "選手名鑑 おまけページ", "みんなの知らない極秘情報がのっているおまけページ。決して誰かに見せてはいけない。", 50000, 0, "", 1, 5, "");
